--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1265,7 +1265,83 @@ Value *InstCombinerImpl::foldEqOfParts(Value *Cmp0, Value *Cmp1, bool IsAnd) {
   Value *RValue = extractIntPart(R, Builder);
   return Builder.CreateICmp(Pred, LValue, RValue);
 }
+/// Fold (icmp pred1 V1, C1) & (icmp pred2 V2, C2) when one comparison implies
+/// the other. This handles masks on the values.
+static Value *foldAndOrOfICmpsWithImplication(ICmpInst *LHS, ICmpInst *RHS,
+                                              bool IsAnd, bool IsLogical,
+                                              InstCombiner::BuilderTy &Builder,
+                                              const SimplifyQuery &Q) {
+  CmpPredicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
+  Value *VL = LHS->getOperand(0), *VR = RHS->getOperand(0);
+  const APInt *CL, *CR;
+  if (!match(LHS->getOperand(1), m_APInt(CL)) ||
+      !match(RHS->getOperand(1), m_APInt(CR)))
+    return nullptr;
+  LLVM_DEBUG(dbgs() << "foldAndOrOfICmpsWithImplication: " << *LHS << " / " << *RHS
+                    << " IsAnd=" << IsAnd << "\n");
+
+  // Look through add of a constant offset.
+  const APInt *OffsetL = nullptr, *OffsetR = nullptr;
+  Value *X;
+  if (match(VL, m_Add(m_Value(X), m_APInt(OffsetL))))
+    VL = X;
+  if (match(VR, m_Add(m_Value(X), m_APInt(OffsetR))))
+    VR = X;
+
+  // Look through and with a constant mask.
+  const APInt *MaskL = nullptr, *MaskR = nullptr;
+  if (match(VL, m_And(m_Value(X), m_APInt(MaskL))))
+    VL = X;
+  if (match(VR, m_And(m_Value(X), m_APInt(MaskR))))
+    VR = X;
+
+  if (VL != VR)
+    return nullptr;

+  // Compute the range of values that satisfy each icmp.
+  auto computeRange = [&](CmpPredicate Pred, const APInt &C,
+                          const APInt *Offset, const APInt *Mask) -> ConstantRange {
+    ConstantRange CR = ConstantRange::makeExactICmpRegion(Pred, C);
+    if (Offset)
+      CR = CR.subtract(*Offset);
+    if (Mask) {
+      // For equality (Pred == ICMP_EQ), the condition (X & Mask) == C.
+      // The set of possible X is C + (bits where Mask is 0 can vary).
+      // This is not contiguous in general, but we can over-approximate as
+      // [C, C | ~Mask] (inclusive). This is safe for subset checking.
+      if (Pred == ICmpInst::ICMP_EQ) {
+        APInt Min = C;
+        APInt Max = C | ~*Mask;
+        if (Min.ule(Max))
+          CR = ConstantRange(Min, Max + 1);
+        else
+          CR = ConstantRange(Max, Min + 1); // wrapped
+      }
+      // For inequality, we cannot easily approximate.
+    }
+    return CR;
+  };
+
+  ConstantRange CRL = computeRange(PredL, *CL, OffsetL, MaskL);
+  ConstantRange CRR = computeRange(PredR, *CR, OffsetR, MaskR);
+
+  if (IsAnd) {
+    // For AND, we need intersection. If one range contains the other,
+    // intersection equals the subset.
+    if (CRL.contains(CRR))
+      return RHS;
+    if (CRR.contains(CRL))
+      return LHS;
+  } else {
+    // For OR, we need union. If one range contains the other,
+    // union equals the superset.
+    if (CRL.contains(CRR))
+      return LHS;
+    if (CRR.contains(CRL))
+      return RHS;
+  }
+  return nullptr;
+}
 /// Reduce logic-of-compares with equality to a constant by substituting a
 /// common operand with the constant. Callers are expected to call this with
 /// Cmp0/Cmp1 switched to handle logic op commutativity.
@@ -3492,7 +3568,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   // This only handles icmp of constants: (icmp1 A, C1) | (icmp2 B, C2).
   if (!LHSC || !RHSC)
     return nullptr;
-
+  // Try to see if one icmp implies the other.
+  if (Value *V = foldAndOrOfICmpsWithImplication(LHS, RHS, IsAnd, IsLogical,
+                                                 Builder, Q))
+    return V;
   // (trunc x) == C1 & (and x, CA) == C2 -> (and x, CA|CMAX) == C1|C2
   // (trunc x) != C1 | (and x, CA) != C2 -> (and x, CA|CMAX) != C1|C2
   // where CMAX is the all ones value for the truncated type,

